{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e3+5;
int n,h,r,x[MAXN],y[MAXN],z[MAXN];
bool f(int x1,int y1,int z1,int x2,int y2,int z2)
{
	return (int)(y2-y1)*(y2-y1)+(int)(x2-x1)*(x2-x1)+(int)(z2-z1)*(z2-z1)<=4*r*r;
}
bool check(int k)
{
	bool vis[MAXN];
    FOR(i,1,n)//need collect taxes
    {
        vis[i]=false;
    }
	queue<int> q;
    //wh(q.size())q.pop();
	q.push(k);
	wh(!q.empty())
	{
		int top=q.front();
		q.pop();
		if(z[top]>=h-r)
		{
			return true;
		}
		FOR(now,1,n)
		{
			if(vis[now])
			{
				continue;
			}
			if(f(x[top],y[top],z[top],x[now],y[now],z[now]))
			{
				q.push(now);
				vis[now]=true;
			}
		}
	}
	return false;
}
void solve()
{
	n=read(),h=read(),r=read();
	FOR(i,1,n)
	{
		x[i]=read(),y[i]=read(),z[i]=read();
	}
	FOR(i,1,n)
	{
		if(z[i]<=r)
		{
			if(check(i))
			{
				Yes
				return;
			}
		}
	}
	No

} 
